    function inferToastTone(color = '') {
        const normalized = String(color).toLowerCase();
        if (normalized === '#ef4444') return 'error';
        if (normalized === '#f59e0b' || normalized === '#f97316') return 'warning';
        if (normalized === '#3b82f6') return 'info';
        if (normalized === '#6b7280') return 'neutral';
        return 'success';
    }

    // Toast tone → RGB. Values are the product's brand palette (popup.css
    // + options.html tokens) so toasts, banners, pills, and cards all share
    // the same semantic color language. Previously these were Tailwind
    // defaults which drifted from the rest of the UI.
    function getToastRgb(tone) {
        switch (tone) {
            case 'error':   return '255,116,128'; // --error  #ff7480
            case 'warning': return '255,190,122'; // --warning #ffbe7a
            case 'info':    return '106,169,255'; // --info   #6aa9ff
            case 'neutral': return '139,151,171'; // --text-muted
            default:        return '53,199,127';  // --success #35c77f
        }
    }

    function getToastBadgeLabel(tone) {
        switch (tone) {
            case 'error': return 'Issue';
            case 'warning': return 'Heads Up';
            case 'info': return 'Update';
            case 'neutral': return 'Notice';
            default: return 'Done';
        }
    }

    function dismissToast(toast, immediate = false) {
        if (!toast) return;
        if (toast._dismissTimer) {
            clearTimeout(toast._dismissTimer);
            toast._dismissTimer = null;
        }
        if (toast._removeTimer) {
            clearTimeout(toast._removeTimer);
            toast._removeTimer = null;
        }
        toast.classList.remove('is-visible');
        if (immediate || window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
            toast.remove();
            return;
        }
        toast._removeTimer = setTimeout(() => {
            if (toast.isConnected) toast.remove();
        }, 180);
    }

    // Global toast notification function with optional action button(s)
    function showToast(message, color = '#22c55e', options = {}) {
        const existingToast = document.querySelector('.ytkit-global-toast');
        if (existingToast) dismissToast(existingToast, true);

        const tone = options.tone || inferToastTone(color);
        const actions = [
            ...(Array.isArray(options.actions) ? options.actions : []),
            ...(options.action ? [options.action] : [])
        ].filter(Boolean).slice(0, 2);
        const durationMs = Math.max(0, Number(options.duration ?? 2.5) * 1000);

        const toast = document.createElement('div');
        toast.className = 'ytkit-global-toast';
        toast.dataset.tone = tone;
        toast.style.setProperty('--ytkit-toast-rgb', getToastRgb(tone));
        toast.style.setProperty('--ytkit-toast-z', String(Z.TOAST));
        toast.setAttribute('role', options.role || (color === '#ef4444' ? 'alert' : 'status'));
        toast.setAttribute('aria-live', options.ariaLive || (color === '#ef4444' ? 'assertive' : 'polite'));
        toast.setAttribute('aria-atomic', 'true');
        toast.tabIndex = -1;

        const badge = document.createElement('span');
        badge.className = 'ytkit-toast-badge';
        badge.textContent = getToastBadgeLabel(tone);

        const body = document.createElement('div');
        body.className = 'ytkit-toast-body';

        const textSpan = document.createElement('span');
        textSpan.className = 'ytkit-toast-message';
        textSpan.textContent = message;
        body.appendChild(textSpan);

        const actionWrap = document.createElement('div');
        actionWrap.className = 'ytkit-toast-actions';

        actions.forEach((action, index) => {
            const actionBtn = document.createElement('button');
            actionBtn.className = `ytkit-toast-action${index > 0 ? ' ytkit-toast-action--secondary' : ''}`;
            actionBtn.type = 'button';
            actionBtn.textContent = action.text || (index === 0 ? 'Undo' : 'Open');
            actionBtn.addEventListener('click', (event) => {
                event.stopPropagation();
                dismissToast(toast);
                action.onClick?.();
            });
            actionWrap.appendChild(actionBtn);
        });

        if (options.dismissible !== false) {
            const closeBtn = document.createElement('button');
            closeBtn.className = 'ytkit-toast-close';
            closeBtn.type = 'button';
            closeBtn.setAttribute('aria-label', 'Dismiss notification');
            closeBtn.textContent = '\u2715';
            closeBtn.addEventListener('click', (event) => {
                event.stopPropagation();
                dismissToast(toast);
            });
            actionWrap.appendChild(closeBtn);
        }
        toast.appendChild(badge);
        toast.appendChild(body);
        toast.appendChild(actionWrap);
        document.body.appendChild(toast);

        let remainingMs = durationMs;
        let dismissAt = Date.now() + remainingMs;
        const pauseDismiss = () => {
            if (!toast._dismissTimer) return;
            clearTimeout(toast._dismissTimer);
            toast._dismissTimer = null;
            remainingMs = Math.max(0, dismissAt - Date.now());
        };
        const resumeDismiss = () => {
            if (!toast.isConnected || remainingMs <= 0 || options.persistent) return;
            dismissAt = Date.now() + remainingMs;
            toast._dismissTimer = setTimeout(() => dismissToast(toast), remainingMs);
        };

        toast.addEventListener('pointerenter', pauseDismiss);
        toast.addEventListener('pointerleave', resumeDismiss);
        toast.addEventListener('focusin', pauseDismiss);
        toast.addEventListener('focusout', (event) => {
            if (!toast.contains(event.relatedTarget)) resumeDismiss();
        });
        toast.addEventListener('keydown', (event) => {
            if (event.key === 'Escape') {
                event.preventDefault();
                dismissToast(toast);
            }
        });

        requestAnimationFrame(() => toast.classList.add('is-visible'));
        if (!options.persistent && durationMs > 0) {
            toast._dismissTimer = setTimeout(() => dismissToast(toast), durationMs);
        }

        return toast;
    }

    // Trigger a custom protocol URI without navigating
    // away from YouTube. An anchor click bypasses YouTube's SPA router.
    function openProtocol(uri, errorMsg) {
        try {
            const a = document.createElement('a');
            a.href = uri;
            a.style.display = 'none';
            document.body.appendChild(a);
            a.click();
            setTimeout(() => {
                try { document.body.removeChild(a); } catch (_) {
                    // reason: node may already be removed by SPA navigation
                }
            }, 200);
        } catch (e) {
            if (errorMsg) showToast(errorMsg, '#ef4444', { duration: 5 });
        }
    }

    // Show a persistent download progress bar anchored to the bottom of the page.
    function showDownloadProgress(id, token, audioOnly) {
        // Remove any existing progress panel for this download
        const panelId = 'ytkit-dl-progress-' + id;
        document.getElementById(panelId)?.remove();

        const panel = document.createElement('div');
        panel.id = panelId;
        panel.className = 'ytkit-dl-progress';
        panel.setAttribute('role', 'status');
        panel.setAttribute('aria-live', 'polite');
        panel.setAttribute('aria-atomic', 'true');
        panel.setAttribute('aria-label', `${audioOnly ? 'Audio' : 'Video'} download progress`);

        if (!document.getElementById('ytkit-dl-anim')) {
            const s = document.createElement('style');
            s.id = 'ytkit-dl-anim';
            s.textContent = `
                @keyframes ytkit-slide-in{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}
            `;
            document.head.appendChild(s);
        }

        const header = document.createElement('div');
        header.className = 'ytkit-dl-progress__header';
        const badge = document.createElement('span');
        badge.className = 'ytkit-dl-progress__badge';
        badge.textContent = `${audioOnly ? 'Audio' : 'Video'} Download`;
        const closeBtn = document.createElement('button');
        closeBtn.type = 'button';
        closeBtn.className = 'ytkit-dl-progress__close';
        closeBtn.setAttribute('aria-label', 'Dismiss download progress');
        closeBtn.textContent = '\u2715';
        header.appendChild(badge);
        header.appendChild(closeBtn);

        const title = document.createElement('div');
        title.className = 'ytkit-dl-progress__title';
        title.textContent = 'Preparing download…';

        const statusRow = document.createElement('div');
        statusRow.className = 'ytkit-dl-progress__status';
        const statePill = document.createElement('span');
        statePill.className = 'ytkit-dl-progress__state';
        statePill.textContent = 'Preparing';
        const statusCopy = document.createElement('span');
        statusCopy.className = 'ytkit-dl-progress__status-copy';
        statusCopy.textContent = audioOnly
            ? 'Connecting to the local audio downloader.'
            : 'Connecting to the local video downloader.';
        statusRow.appendChild(statePill);
        statusRow.appendChild(statusCopy);

        const bar = document.createElement('div');
        bar.className = 'ytkit-dl-progress__bar';
        const fill = document.createElement('div');
        fill.className = 'ytkit-dl-progress__fill';
        bar.appendChild(fill);

        const meta = document.createElement('div');
        meta.className = 'ytkit-dl-progress__meta';
        const pct = document.createElement('span');
        pct.className = 'ytkit-dl-progress__stat';
        pct.textContent = '0%';
        const spd = document.createElement('span');
        spd.className = 'ytkit-dl-progress__stat';
        spd.textContent = 'Waiting';
        const eta = document.createElement('span');
        eta.className = 'ytkit-dl-progress__stat';
        eta.textContent = 'Queue';
        meta.appendChild(pct);
        meta.appendChild(spd);
        meta.appendChild(eta);

        const actions = document.createElement('div');
        actions.className = 'ytkit-dl-progress__actions';
        actions.hidden = true;
        const repairBtn = document.createElement('button');
        repairBtn.type = 'button';
        repairBtn.className = 'ytkit-dl-progress__action';
        repairBtn.textContent = 'Repair downloader';
        repairBtn.setAttribute('aria-label', 'Open local downloader repair steps');
        repairBtn.addEventListener('click', () => MediaDLManager.showInstallPrompt('retry'));
        actions.appendChild(repairBtn);

        const setProgressState = (tone, label, copy, showRepair = false) => {
            panel.dataset.state = tone;
            statePill.textContent = label;
            statusCopy.textContent = copy;
            actions.hidden = !showRepair;
        };
        setProgressState(
            'pending',
            'Preparing',
            audioOnly
                ? 'Connecting to the local audio downloader.'
                : 'Connecting to the local video downloader.'
        );

        panel.appendChild(header);
        panel.appendChild(title);
        panel.appendChild(statusRow);
        panel.appendChild(bar);
        panel.appendChild(meta);
        panel.appendChild(actions);
        document.body.appendChild(panel);

        // Self-scheduling poll loop (setTimeout chain) prevents overlap when a
        // single poll exceeds the poll interval — setInterval would have fired
        // a second poll while the first was still awaiting, doubling load on
        // the local downloader. `stopped` is an explicit kill switch so error
        // branches, success branches, and the close button all short-circuit
        // future work.
        let pollTimer = null;
        let stopped = false;
        // Transient errors (server doing heavy CPU work, yt-dlp brief stall,
        // quick network blip) previously tore down the progress UI on the very
        // first failure. Tolerate a small streak before declaring the download
        // disconnected so real downloads don't disappear on a momentary hiccup.
        let consecutiveErrors = 0;
        const MAX_CONSECUTIVE_ERRORS = 5;

        const stopPolling = () => {
            stopped = true;
            if (pollTimer) { clearTimeout(pollTimer); pollTimer = null; }
        };

        closeBtn.addEventListener('click', () => {
            // Stop polling immediately when the user closes the panel so we
            // don't keep hitting the local downloader for a UI that is gone.
            stopPolling();
            panel.remove();
        });

        async function poll() {
            pollTimer = null;
            if (stopped) return;
            if (!panel.isConnected) { stopPolling(); return; }
            try {
                const { data } = await extensionFetchJson({
                    method: 'GET',
                    url: MediaDLManager.baseUrl() + '/status/' + id,
                    headers: { 'X-Auth-Token': token },
                    timeout: 3000
                });
                if (stopped || !fill.isConnected) { stopPolling(); return; }
                consecutiveErrors = 0;

                if (data.title) title.textContent = data.title;
                const p = Math.min(data.progress || 0, 100);
                fill.style.width = p + '%';
                pct.textContent = p.toFixed(1) + '%';
                spd.textContent = data.speed || 'Local';
                eta.textContent = data.eta ? 'ETA ' + data.eta : (p >= 99 ? 'Wrapping up' : 'In progress');
                setProgressState(
                    'active',
                    data.status === 'processing' ? 'Finishing' : 'Downloading',
                    data.eta
                        ? `${p.toFixed(1)}% complete. ${data.eta} remaining.`
                        : `${p.toFixed(1)}% complete. Stay on YouTube while the local downloader finishes.`
                );

                if (data.status === 'done' || data.status === 'complete') {
                    stopPolling();
                    fill.style.width = '100%';
                    fill.classList.remove('is-error');
                    fill.classList.add('is-success');
                    pct.textContent = '100%';
                    spd.textContent = '';
                    eta.textContent = 'Ready';
                    setProgressState('success', 'Complete', 'The local downloader finished successfully.');
                    setTimeout(() => panel.remove(), 4000);
                    return;
                }
                if (data.status === 'error' || data.status === 'failed' || data.status === 'cancelled') {
                    stopPolling();
                    const failureReason = data.error || 'Local downloader failed';
                    fill.classList.remove('is-success');
                    fill.classList.add('is-error');
                    title.textContent = failureReason;
                    pct.textContent = 'Failed';
                    spd.textContent = '';
                    eta.textContent = '';
                    const needsRepair = /cookie|yt-dlp|unauthorized|local downloader/i.test(failureReason);
                    setProgressState('error', 'Needs Attention', failureReason, needsRepair);
                    showToast(failureReason, '#ef4444', { duration: 6 });
                    if (needsRepair) {
                        MediaDLManager.showInstallPrompt('retry');
                    }
                    return;
                }
            } catch (err) {
                consecutiveErrors += 1;
                DebugManager.log(
                    'Download',
                    `Poll failed (${consecutiveErrors}/${MAX_CONSECUTIVE_ERRORS}): ${err.message}`
                );
                if (consecutiveErrors >= MAX_CONSECUTIVE_ERRORS) {
                    stopPolling();
                    fill.classList.remove('is-success');
                    fill.classList.add('is-error');
                    title.textContent = 'Connection to downloader lost';
                    pct.textContent = 'Error';
                    spd.textContent = '';
                    eta.textContent = '';
                    setProgressState('error', 'Connection Lost', 'Astra Deck lost contact with the local downloader. Choose Repair downloader to recover.', true);
                    showToast('Lost contact with the local downloader.', '#ef4444', { duration: 5 });
                    return;
                }
                // Transient error — surface a gentle status update but keep polling.
                setProgressState(
                    'active',
                    'Reconnecting',
                    'Momentary hiccup with the local downloader — retrying automatically.'
                );
            }
            if (!stopped && panel.isConnected) {
                // Slight backoff on errors so we don't hammer a struggling server.
                const nextDelay = consecutiveErrors > 0 ? 1500 : 750;
                pollTimer = setTimeout(poll, nextDelay);
            }
        }

        poll();
    }

    // ── MediaDL Server Manager ──
    // Caches server availability, provides install/status helpers, and auto-start logic.
    const MediaDLManager = {
        _status: null, // null = unknown, 'running', 'not-installed'
        _token: null,
        _lastCheck: 0,
        _serverVersion: null,
        _autoStartAttempted: false,
        _CHECK_INTERVAL: 30000, // Re-check every 30s

        // GitHub raw URL for the compiled installer exe
        INSTALLER_URL: 'https://raw.githubusercontent.com/SysAdminDoc/Astra-Deck/main/AstraDownloader.exe',
        INSTALLER_FILE_NAME: 'AstraDownloader.exe',
        INSTALLER_COMMAND: "powershell -NoProfile -ExecutionPolicy Bypass -Command \"[Net.ServicePointManager]::SecurityProtocol=[Net.SecurityProtocolType]::Tls12; $out=Join-Path $env:TEMP 'AstraDownloader.exe'; Invoke-WebRequest -UseBasicParsing -Uri 'https://raw.githubusercontent.com/SysAdminDoc/Astra-Deck/main/AstraDownloader.exe' -OutFile $out; Start-Process $out\"",
        INSTALLER_RUN_HINT: 'Open Downloads and double-click the setup file to install.',

        // Ports the server may have bound to — must match AstraDownloader.PORT_FALLBACKS.
        // The server prefers 9751 but falls back when Windows (e.g. Hyper-V) blocks it.
        _PORT_CANDIDATES: [9751, 9761, 9771, 9781, 9791, 9851],
        _port: 9751,
        _SERVICE_ID: 'astra-downloader',

        // Base URL for server calls. Always reflects the currently discovered port.
        baseUrl() { return 'http://127.0.0.1:' + this._port; },

        _isAstraDownloaderHealth(data) {
            if (!data || !data.token) return false;
            if (data.service === this._SERVICE_ID) return true;
            // Backward-compatible acceptance for hardened builds that predate
            // the explicit service id but still expose the Astra-only health schema.
            return data.token_required === true && Number.isInteger(data.port);
        },

        // Quick health check — returns { ok, token, version, port } or { ok: false }.
        // Tries the cached port first, then probes the fallback list.
        async check(force) {
            const now = Date.now();
            if (!force && this._status === 'running' && this._token && (now - this._lastCheck < this._CHECK_INTERVAL)) {
                return { ok: true, token: this._token, version: this._serverVersion, port: this._port };
            }

            const tryPort = async (port) => {
                try {
                    const { data } = await extensionFetchJson({
                        method: 'GET',
                        url: 'http://127.0.0.1:' + port + '/health',
                        headers: { 'X-MDL-Client': 'MediaDL' },
                        timeout: 1500
                    });
                    if (this._isAstraDownloaderHealth(data)) return data;
                    if (data && data.token) {
                        DebugManager.log('MediaDL', `Ignoring non-Astra downloader response on port ${port}`);
                    }
                } catch (_) {
                    // reason: port may be occupied by unrelated local service; skip
                }
                return null;
            };

            // Try previously-known port first, then all others.
            const order = [this._port, ...this._PORT_CANDIDATES.filter(p => p !== this._port)];
            for (const port of order) {
                const data = await tryPort(port);
                if (data) {
                    this._port = port;
                    this._status = 'running';
                    this._token = data.token;
                    this._serverVersion = data.version || null;
                    this._lastCheck = now;
                    DebugManager.log('MediaDL', `Server running on port ${port} (v${this._serverVersion || '?'}, ${data.downloads || 0} active)`);
                    return { ok: true, token: data.token, version: this._serverVersion, port };
                }
            }

            this._status = 'not-installed';
            this._token = null;
            return { ok: false };
        },

        // Try to auto-start the server via mediadl:// protocol and wait for it.
        // Attempts the protocol launch once per page load, then polls health up to
        // `retries` times. If the protocol handler isn't registered, the browser
        // silently ignores it — no error dialog.
        async tryAutoStart(retries = 4) {
            if (this._autoStartAttempted) {
                // Already tried this session — just do a single quick recheck
                return this.check(true);
            }
            this._autoStartAttempted = true;
            DebugManager.log('MediaDL', 'Attempting auto-start via mediadl:// protocol…');
            showToast('Starting Astra Downloader…', '#3b82f6', { duration: 4 });
            openProtocol('mediadl://start');
            // Poll for server readiness
            for (let i = 0; i < retries; i++) {
                await new Promise(r => setTimeout(r, 1500));
                const result = await this.check(true);
                if (result.ok) {
                    showToast('Astra Downloader started!', '#22c55e', { duration: 2 });
                    return result;
                }
            }
            DebugManager.log('MediaDL', 'Auto-start failed — server did not respond');
            return { ok: false };
        },

        // Reset auto-start flag so the next download re-attempts.
        // Called from the "Retry" button after user installs.
        resetAutoStart() { this._autoStartAttempted = false; this._status = null; },

        async copyInstallCommand() {
            try {
                await navigator.clipboard.writeText(this.INSTALLER_COMMAND);
                return true;
            } catch (_) {
                return false;
            }
        },

        async downloadInstaller() {
            try {
                await triggerDownload(this.INSTALLER_URL, this.INSTALLER_FILE_NAME, { showInFolder: true });
                return true;
            } catch (_) {
                return false;
            }
        },

        async runInstallAssist() {
            const copied = await this.copyInstallCommand();
            const downloaded = await this.downloadInstaller();
            if (!downloaded) {
                void openExternalUrl(this.INSTALLER_URL).catch(() => {});
            }
            showToast(
                copied
                    ? `Setup file ready. ${this.INSTALLER_RUN_HINT} The fallback command was copied too.`
                    : `Setup file ready. ${this.INSTALLER_RUN_HINT}`,
                '#22c55e',
                { duration: 8 }
            );
            return { copied, downloaded };
        },

        get isRunning() { return this._status === 'running'; },
        get token() { return this._token; },

        // Show install / retry prompt panel.
        // Two modes:
        //   'install' — user has never installed MediaDL (default)
        //   'retry'   — auto-start failed, might just need a kick
        showInstallPrompt(mode) {
            const existing = document.getElementById('ytkit-mediadl-install-prompt');
            if (existing) existing.remove(); // replace with fresh state

            const isRetryMode = mode === 'retry';

            const prompt = document.createElement('div');
            prompt.id = 'ytkit-mediadl-install-prompt';
            prompt.className = 'ytkit-install-prompt';
            prompt.dataset.mode = isRetryMode ? 'repair' : 'install';
            prompt.dataset.state = isRetryMode ? 'warning' : 'ready';
            prompt.setAttribute('role', 'region');
            prompt.setAttribute('aria-labelledby', 'ytkit-install-prompt-title');
            prompt.setAttribute('aria-describedby', 'ytkit-install-prompt-desc');

            // ── Header ──
            const header = document.createElement('div');
            header.className = 'ytkit-install-prompt__header';
            const heading = document.createElement('div');
            heading.className = 'ytkit-install-prompt__heading';
            const eyebrow = document.createElement('span');
            eyebrow.className = 'ytkit-install-prompt__eyebrow';
            eyebrow.textContent = isRetryMode ? 'Connection check' : 'Local downloads';
            const titleEl = document.createElement('span');
            titleEl.id = 'ytkit-install-prompt-title';
            titleEl.className = 'ytkit-install-prompt__title';
            titleEl.textContent = isRetryMode ? 'Reconnect the local downloader' : 'Set up local downloads';
            const closeBtn = document.createElement('button');
            closeBtn.className = 'ytkit-install-prompt__close';
            closeBtn.type = 'button';
            closeBtn.setAttribute('aria-label', 'Close local downloader prompt');
            closeBtn.textContent = '\u2715';
            closeBtn.onclick = () => prompt.remove();
            heading.appendChild(eyebrow);
            heading.appendChild(titleEl);
            header.appendChild(heading);
            header.appendChild(closeBtn);

            // ── Description ──
            const desc = document.createElement('p');
            desc.id = 'ytkit-install-prompt-desc';
            desc.className = 'ytkit-install-prompt__desc';
            desc.textContent = isRetryMode
                ? 'Astra Deck cannot reach the downloader service right now. Start it again if it is installed, or run setup to repair the local service.'
                : 'Enable reliable audio and video downloads by installing Astra Downloader on this device. One setup covers future downloads.';

            const note = document.createElement('div');
            note.className = 'ytkit-install-prompt__note';
            note.setAttribute('role', 'status');
            note.setAttribute('aria-live', 'polite');
            note.textContent = isRetryMode
                ? 'Fastest path: start the service again first. If it still does not respond, run setup to repair the install.'
                : 'Recommended path: download setup, open the file, then return here and check again.';

            const steps = document.createElement('ol');
            steps.className = 'ytkit-install-prompt__steps';
            [
                isRetryMode
                    ? 'Start the service again if the downloader is already installed.'
                    : 'Download the Astra Downloader setup file.',
                'Open the setup file from Downloads and finish installation.',
                'Choose Check again so Astra Deck can confirm the service is ready.'
            ].forEach((copy) => {
                const item = document.createElement('li');
                item.className = 'ytkit-install-prompt__step';
                item.textContent = copy;
                steps.appendChild(item);
            });

            // ── Buttons ──
            const btnCol = document.createElement('div');
            btnCol.className = 'ytkit-install-prompt__actions';

            // Button helper
            const setPromptButtonState = (button, label, tone = '') => {
                const labelEl = button.querySelector('.ytkit-install-prompt__btn-label');
                if (labelEl) labelEl.textContent = label;
                const detail = button.dataset.detail || '';
                button.setAttribute('aria-label', detail ? `${label}. ${detail}` : label);
                button.classList.remove('is-success', 'is-danger');
                if (tone === 'success') button.classList.add('is-success');
                if (tone === 'danger') button.classList.add('is-danger');
            };

            const setPromptNote = (message, tone = 'ready') => {
                prompt.dataset.state = tone;
                note.textContent = message;
            };

            const makeBtn = (text, variant, onClick, detail = '') => {
                const b = document.createElement('button');
                b.type = 'button';
                b.className = `ytkit-install-prompt__btn ytkit-install-prompt__btn--${variant}`;
                b.dataset.detail = detail;
                b.setAttribute('aria-label', detail ? `${text}. ${detail}` : text);
                const copy = document.createElement('span');
                copy.className = 'ytkit-install-prompt__btn-copy';
                const label = document.createElement('span');
                label.className = 'ytkit-install-prompt__btn-label';
                label.textContent = text;
                copy.appendChild(label);
                if (detail) {
                    const meta = document.createElement('span');
                    meta.className = 'ytkit-install-prompt__btn-meta';
                    meta.textContent = detail;
                    copy.appendChild(meta);
                }
                b.appendChild(copy);
                b.onclick = onClick;
                return b;
            };

            // 1. Retry / Start Server
            if (isRetryMode) {
                const retryBtn = makeBtn('Start service', 'primary', async () => {
                    setPromptNote('Starting the local downloader service…', 'warning');
                    setPromptButtonState(retryBtn, 'Starting…');
                    retryBtn.disabled = true;
                    retryBtn.setAttribute('aria-busy', 'true');
                    this.resetAutoStart();
                    const result = await this.tryAutoStart(5);
                    if (result.ok) {
                        showToast('Astra Downloader is running!', '#22c55e', { duration: 3 });
                        prompt.remove();
                    } else {
                        retryBtn.setAttribute('aria-busy', 'false');
                        setPromptNote('The service did not respond. Run setup below to repair the local downloader, then check again.', 'error');
                        setPromptButtonState(retryBtn, 'Try again', 'danger');
                        retryBtn.disabled = false;
                    }
                }, 'Fastest fix if the downloader is installed but idle.');
                btnCol.appendChild(retryBtn);
            }

            // 2. Copy Install Command
            const copyBtn = makeBtn('Download setup', 'accent', async () => {
                setPromptNote('Downloading the setup file…', 'warning');
                setPromptButtonState(copyBtn, 'Downloading setup…');
                copyBtn.disabled = true;
                copyBtn.setAttribute('aria-busy', 'true');
                const result = await this.runInstallAssist();
                copyBtn.setAttribute('aria-busy', 'false');
                setPromptButtonState(copyBtn, result.downloaded ? 'Setup ready' : 'Open setup file', result.downloaded ? 'success' : '');
                setPromptNote(
                    result.downloaded
                        ? 'Setup downloaded. Open the file, finish installation, then choose Check again.'
                        : 'The setup file should be open. Finish installation, then choose Check again.',
                    'success'
                );
                copyBtn.disabled = false;
            }, 'Recommended. Installs or repairs the local downloader.');
            btnCol.appendChild(copyBtn);

            // 3. Copy PowerShell command
            const dlBtn = makeBtn('Copy fallback command', 'ghost', async () => {
                const copied = await this.copyInstallCommand();
                if (copied) {
                    setPromptButtonState(dlBtn, 'Command copied', 'success');
                    setPromptNote('Fallback command copied. Use it in PowerShell only if the setup file cannot run.', 'success');
                    showToast('Fallback install command copied. Use it only if you cannot run the downloaded setup file.', '#3b82f6', { duration: 6 });
                    setTimeout(() => { setPromptButtonState(dlBtn, 'Copy fallback command'); }, 3500);
                } else {
                    void openExternalUrl(this.INSTALLER_URL).catch(() => {});
                }
            }, 'Use only if the downloaded setup file cannot run.');
            btnCol.appendChild(dlBtn);

            // 4. "I just installed it" — re-check
            const recheckBtn = makeBtn('Check again', 'ghost', async () => {
                setPromptNote('Checking for the local downloader service…', 'warning');
                setPromptButtonState(recheckBtn, 'Checking…');
                recheckBtn.disabled = true;
                recheckBtn.setAttribute('aria-busy', 'true');
                this.resetAutoStart();
                const result = await this.tryAutoStart(5);
                if (result.ok) {
                    showToast('Local downloader is ready.', '#22c55e', { duration: 4 });
                    prompt.remove();
                } else {
                    recheckBtn.setAttribute('aria-busy', 'false');
                    setPromptButtonState(recheckBtn, 'Not detected yet', 'danger');
                    setPromptNote('Setup was not detected yet. Make sure the installer finished, then check again.', 'error');
                    recheckBtn.disabled = false;
                    setTimeout(() => { setPromptButtonState(recheckBtn, 'Check again'); }, 4000);
                }
            }, 'Use this after running the setup file.');
            btnCol.appendChild(recheckBtn);

            // 5. Dismiss
            if (!isRetryMode) {
                const dismissBtn = makeBtn('Skip for now', 'quiet', () => {
                    prompt.remove();
                    storageWrite('ytkit_mediadl_prompt_dismissed', true);
                });
                btnCol.appendChild(dismissBtn);
            }

            prompt.appendChild(header);
            prompt.appendChild(desc);
            prompt.appendChild(note);
            prompt.appendChild(steps);
            prompt.appendChild(btnCol);
            document.body.appendChild(prompt);
        }
    };

    // Legacy wrapper — still used by autoStart retry logic
    function mediaDLDownload(videoUrl, audioOnly) {
        DebugManager.log('MediaDL', `Download requested (legacy): ${videoUrl} (audio=${audioOnly})`);
        ytKitDownload(videoUrl, audioOnly);
    }

    // Main download handler — the extension now relies exclusively on the local
    // yt-dlp service. If the server is unavailable, we guide the user through the
    // single install path instead of branching into web or direct-download fallbacks.
    //
    // opts: { format?, outputDir? } — optional overrides from the download popup
    let _downloadInProgress = false;
    async function ytKitDownload(videoUrl, audioOnly, opts = {}) {
        if (_downloadInProgress) {
            showToast('A download is already in progress.', '#f59e0b', { duration: 3 });
            return;
        }
        _downloadInProgress = true;
        DebugManager.log('Download', `Download requested: ${videoUrl} (audio=${audioOnly}, format=${opts.format || 'default'}, dir=${opts.outputDir || 'default'})`);
        showToast(audioOnly ? 'Preparing your audio download…' : 'Preparing your video download…', '#3b82f6', { duration: 2 });

        let mdl = await MediaDLManager.check();
        if (!mdl.ok) {
            mdl = await MediaDLManager.tryAutoStart();
        }
        if (!mdl.ok) {
            DebugManager.log('Download', 'Local yt-dlp server unavailable');
            showToast('Install the local downloader to enable downloads.', '#f59e0b', { duration: 4 });
            if (!storageRead('ytkit_mediadl_prompt_dismissed', false)) {
                MediaDLManager.showInstallPrompt(MediaDLManager._autoStartAttempted ? 'retry' : 'install');
            }
            _downloadInProgress = false;
            return;
        }

        try {
            await _mediaDLSendDownload(videoUrl, audioOnly, mdl.token, opts);
        } catch (e) {
            DebugManager.log('Download', `MediaDL download failed: ${e.message}`);
            showToast('Local downloader request failed.', '#ef4444', { duration: 4 });
            MediaDLManager.showInstallPrompt('retry');
        } finally {
            _downloadInProgress = false;
        }
    }

    async function _mediaDLSendDownload(videoUrl, audioOnly, token, opts = {}) {
        DebugManager.log('MediaDL', `Sending download: ${videoUrl} (audio=${audioOnly})`);
        const s = appState?.settings;
        const payload = {
            url: videoUrl,
            audioOnly: !!audioOnly,
            quality: s?.downloadQuality || 'best',
            format: opts.format || (audioOnly ? (s?.downloadAudioFormat || 'mp3') : (s?.downloadVideoFormat || 'mp4'))
        };
        if (opts.outputDir) payload.outputDir = opts.outputDir;

        // Extract cookies via the extension cookie bridge.
        // Sends all YouTube cookies (including httpOnly) to the server for yt-dlp.
        const sendDownload = async () => {
            try {
                const { response, data: resp } = await extensionFetchJson({
                    method: 'POST',
                    url: MediaDLManager.baseUrl() + '/download',
                    headers: { 'Content-Type': 'application/json', 'X-Auth-Token': token },
                    data: JSON.stringify(payload),
                    timeout: 5000
                });
                DebugManager.log('MediaDL', `Download response: ${response.status} - ${response.responseText}`);
                if (resp.id) {
                    showDownloadProgress(resp.id, token, audioOnly);
                } else {
                    showToast('MediaDL: ' + (resp.error || 'Unknown error'), '#ef4444', { duration: 5 });
                }
            } catch (error) {
                DebugManager.log('MediaDL', `Download request error: ${error.message}`);
                showToast(error.isTimeout ? 'MediaDL request timed out' : 'MediaDL download request failed', '#ef4444', { duration: 5 });
            }
        };

        if (browserCookies.listAsync) {
            try {
                const cookies = await browserCookies.listAsync({ domain: '.youtube.com' });
                if (cookies.length > 0) {
                    payload.cookies = cookies.map(c => ({
                        domain: c.domain, name: c.name, value: c.value,
                        path: c.path || '/', secure: !!c.secure,
                        httpOnly: !!c.httpOnly,
                        expirationDate: c.expirationDate || 0
                    }));
                    DebugManager.log('MediaDL', `Attached ${cookies.length} cookies for yt-dlp`);
                } else {
                    DebugManager.log('MediaDL', 'Extension cookie bridge returned no cookies (permission may not be granted)');
                }
            } catch (e) {
                DebugManager.log('MediaDL', `Extension cookie bridge error: ${e.message}`);
            }
        }

        await sendDownload();
    }

    // ── Download Options Popup ──
    // Shows format, quality, and directory controls when the download button is clicked
    const VIDEO_FORMATS = [
        { value: 'mp4',  label: 'MP4',  desc: 'Universal, best compat' },
        { value: 'mkv',  label: 'MKV',  desc: 'Lossless container' },
        { value: 'webm', label: 'WebM', desc: 'Web-optimized' }
    ];
    const AUDIO_FORMATS = [
        { value: 'mp3',  label: 'MP3',  desc: '320kbps, universal' },
        { value: 'm4a',  label: 'M4A',  desc: 'AAC, Apple-friendly' },
        { value: 'opus', label: 'Opus', desc: 'Smaller, high quality' },
        { value: 'flac', label: 'FLAC', desc: 'Lossless audio' },
        { value: 'wav',  label: 'WAV',  desc: 'Uncompressed PCM' }
    ];
    const QUALITY_OPTIONS = [
        { value: 'best', label: 'Best' },
        { value: '2160', label: '4K' },
        { value: '1440', label: '1440p' },
        { value: '1080', label: '1080p' },
        { value: '720',  label: '720p' },
        { value: '480',  label: '480p' }
    ];

    let _dlPopup = null;
    let _dlPopupCleanup = null;

    function _closeDlPopup() {
        if (_dlPopupCleanup) { _dlPopupCleanup(); _dlPopupCleanup = null; }
        if (_dlPopup) { _dlPopup.remove(); _dlPopup = null; }
    }

    async function _fetchServerConfig(token) {
        try {
            const { data } = await extensionFetchJson({
                method: 'GET',
                url: MediaDLManager.baseUrl() + '/config',
                headers: { 'X-Auth-Token': token },
                timeout: 2000
            });
            return data;
        } catch (_) { return null; }
    }

    function showDownloadPopup(anchorEl) {
        _closeDlPopup();

        const s = appState?.settings || {};
        let selectedMode = 'video'; // 'video' or 'audio'
        let selectedVideoFormat = s.downloadVideoFormat || 'mp4';
        let selectedAudioFormat = s.downloadAudioFormat || 'mp3';
        let selectedQuality = s.downloadQuality || 'best';
        let customDir = '';
        let dlBtn = null;
        let chipRowCount = 0;
        const syncDownloadCta = () => {
            if (!dlBtn) return;
            const isAudio = selectedMode === 'audio';
            const format = isAudio ? selectedAudioFormat : selectedVideoFormat;
            const quality = QUALITY_OPTIONS.find(q => q.value === selectedQuality)?.label || selectedQuality;
            dlBtn.textContent = isAudio ? 'Download audio' : 'Download video';
            dlBtn.setAttribute(
                'aria-label',
                isAudio
                    ? `Download audio as ${format.toUpperCase()}`
                    : `Download video as ${format.toUpperCase()} at ${quality}`
            );
        };

        const popup = document.createElement('div');
        popup.className = 'ytkit-dl-popup';
        popup.setAttribute('role', 'dialog');
        popup.setAttribute('aria-label', 'Download options');

        // ── Header ──
        const header = document.createElement('div');
        header.className = 'ytkit-dl-popup__header';
        const title = document.createElement('span');
        title.className = 'ytkit-dl-popup__title';
        title.textContent = 'Download options';
        const closeBtn = document.createElement('button');
        closeBtn.type = 'button';
        closeBtn.className = 'ytkit-dl-popup__close';
        closeBtn.setAttribute('aria-label', 'Close');
        closeBtn.textContent = '\u2715';
        closeBtn.addEventListener('click', _closeDlPopup);
        header.appendChild(title);
        header.appendChild(closeBtn);
        popup.appendChild(header);

        // ── Mode tabs (Video / Audio) ──
        const tabs = document.createElement('div');
        tabs.className = 'ytkit-dl-popup__tabs';
        tabs.setAttribute('role', 'tablist');
        tabs.setAttribute('aria-label', 'Download type');
        const vidTab = document.createElement('button');
        vidTab.type = 'button';
        vidTab.className = 'ytkit-dl-popup__tab is-active';
        vidTab.setAttribute('role', 'tab');
        vidTab.setAttribute('aria-selected', 'true');
        vidTab.textContent = 'Video';
        const audTab = document.createElement('button');
        audTab.type = 'button';
        audTab.className = 'ytkit-dl-popup__tab';
        audTab.setAttribute('role', 'tab');
        audTab.setAttribute('aria-selected', 'false');
        audTab.textContent = 'Audio only';

        const updateTabs = () => {
            vidTab.classList.toggle('is-active', selectedMode === 'video');
            audTab.classList.toggle('is-active', selectedMode === 'audio');
            vidTab.setAttribute('aria-selected', String(selectedMode === 'video'));
            audTab.setAttribute('aria-selected', String(selectedMode === 'audio'));
            qualityRow.hidden = selectedMode === 'audio';
            videoFormatRow.hidden = selectedMode !== 'video';
            audioFormatRow.hidden = selectedMode !== 'audio';
            syncDownloadCta();
        };
        vidTab.addEventListener('click', () => { selectedMode = 'video'; updateTabs(); });
        audTab.addEventListener('click', () => { selectedMode = 'audio'; updateTabs(); });
        tabs.appendChild(vidTab);
        tabs.appendChild(audTab);
        popup.appendChild(tabs);

        // ── Body ──
        const body = document.createElement('div');
        body.className = 'ytkit-dl-popup__body';

        // Format rows
        const makeChipRow = (label, items, selected, onSelect) => {
            const row = document.createElement('div');
            row.className = 'ytkit-dl-popup__row';
            const lbl = document.createElement('div');
            lbl.className = 'ytkit-dl-popup__label';
            lbl.id = `ytkit-dl-popup-row-${++chipRowCount}`;
            lbl.textContent = label;
            row.appendChild(lbl);
            const chips = document.createElement('div');
            chips.className = 'ytkit-dl-popup__chips';
            chips.setAttribute('role', 'group');
            chips.setAttribute('aria-labelledby', lbl.id);
            items.forEach(item => {
                const chip = document.createElement('button');
                chip.type = 'button';
                chip.className = 'ytkit-dl-popup__chip' + (item.value === selected ? ' is-active' : '');
                chip.dataset.value = item.value;
                chip.title = item.desc || '';
                chip.textContent = item.label;
                chip.setAttribute('aria-pressed', String(item.value === selected));
                chip.setAttribute('aria-label', item.desc ? `${item.label}. ${item.desc}` : item.label);
                chip.addEventListener('click', () => {
                    chips.querySelectorAll('.ytkit-dl-popup__chip').forEach(c => {
                        c.classList.remove('is-active');
                        c.setAttribute('aria-pressed', 'false');
                    });
                    chip.classList.add('is-active');
                    chip.setAttribute('aria-pressed', 'true');
                    onSelect(item.value);
                    syncDownloadCta();
                });
                chips.appendChild(chip);
            });
            row.appendChild(chips);
            return row;
        };

        const videoFormatRow = makeChipRow('Format', VIDEO_FORMATS, selectedVideoFormat, v => { selectedVideoFormat = v; });
        const audioFormatRow = makeChipRow('Format', AUDIO_FORMATS, selectedAudioFormat, v => { selectedAudioFormat = v; });
        audioFormatRow.hidden = true;
        const qualityRow = makeChipRow('Quality', QUALITY_OPTIONS, selectedQuality, v => { selectedQuality = v; });

        body.appendChild(videoFormatRow);
        body.appendChild(audioFormatRow);
        body.appendChild(qualityRow);

        // ── Directory row ──
        const dirRow = document.createElement('div');
        dirRow.className = 'ytkit-dl-popup__row';
        const dirLabel = document.createElement('div');
        dirLabel.className = 'ytkit-dl-popup__label';
        dirLabel.id = 'ytkit-dl-popup-save-to-label';
        dirLabel.textContent = 'Save to';
        dirRow.appendChild(dirLabel);
        const dirWrap = document.createElement('div');
        dirWrap.className = 'ytkit-dl-popup__dir-wrap';
        dirWrap.setAttribute('role', 'group');
        dirWrap.setAttribute('aria-labelledby', dirLabel.id);
        const dirDisplay = document.createElement('span');
        dirDisplay.className = 'ytkit-dl-popup__dir-path';
        dirDisplay.textContent = 'Default (Downloads)';
        const dirInput = document.createElement('input');
        dirInput.type = 'text';
        dirInput.className = 'ytkit-dl-popup__dir-input';
        dirInput.id = 'ytkit-dl-popup-custom-dir';
        dirInput.setAttribute('aria-label', 'Custom download folder');
        dirInput.placeholder = 'C:\\Users\\...\\Videos';
        dirInput.spellcheck = false;
        dirInput.autocomplete = 'off';
        dirInput.hidden = true;
        dirInput.addEventListener('input', () => { customDir = dirInput.value.trim(); });
        const dirToggle = document.createElement('button');
        dirToggle.type = 'button';
        dirToggle.className = 'ytkit-dl-popup__dir-btn';
        dirToggle.textContent = 'Change';
        dirToggle.setAttribute('aria-controls', dirInput.id);
        dirToggle.setAttribute('aria-expanded', 'false');
        dirToggle.setAttribute('aria-label', 'Choose a custom download folder');
        dirToggle.addEventListener('click', () => {
            const showing = !dirInput.hidden;
            dirInput.hidden = showing;
            dirDisplay.hidden = !showing;
            dirToggle.textContent = showing ? 'Change' : 'Default';
            dirToggle.setAttribute('aria-expanded', String(!showing));
            dirToggle.setAttribute('aria-label', showing ? 'Choose a custom download folder' : 'Use the default Downloads folder');
            if (showing) { customDir = ''; dirInput.value = ''; }
            else { dirInput.focus(); }
        });
        dirWrap.appendChild(dirDisplay);
        dirWrap.appendChild(dirInput);
        dirWrap.appendChild(dirToggle);
        dirRow.appendChild(dirWrap);
        body.appendChild(dirRow);

        popup.appendChild(body);

        // ── Footer: Download button ──
        const footer = document.createElement('div');
        footer.className = 'ytkit-dl-popup__footer';
        dlBtn = document.createElement('button');
        dlBtn.type = 'button';
        dlBtn.className = 'ytkit-dl-popup__go';
        syncDownloadCta();
        dlBtn.addEventListener('click', () => {
            const isAudio = selectedMode === 'audio';
            const format = isAudio ? selectedAudioFormat : selectedVideoFormat;
            const opts = { format };
            if (customDir) opts.outputDir = customDir;
            // Persist selections
            if (appState?.settings) {
                appState.settings.downloadQuality = selectedQuality;
                if (isAudio) appState.settings.downloadAudioFormat = selectedAudioFormat;
                else appState.settings.downloadVideoFormat = selectedVideoFormat;
                storageWriteJSON('ytSuiteSettings', appState.settings);
            }
            _closeDlPopup();
            ytKitDownload(window.location.href, isAudio, opts);
        });
        footer.appendChild(dlBtn);
        popup.appendChild(footer);

        // Position relative to anchor
        document.body.appendChild(popup);
        _dlPopup = popup;

        // Position above the anchor
        if (anchorEl) {
            const r = anchorEl.getBoundingClientRect();
            const pw = popup.offsetWidth;
            const ph = popup.offsetHeight;
            let left = r.left + r.width / 2 - pw / 2;
            let top = r.top - ph - 8;
            if (top < 8) top = r.bottom + 8;
            if (left < 8) left = 8;
            if (left + pw > window.innerWidth - 8) left = window.innerWidth - pw - 8;
            popup.style.left = left + 'px';
            popup.style.top = top + 'px';
        }

        // Outside click handler
        const outsideClick = (e) => {
            if (!popup.contains(e.target) && e.target !== anchorEl) _closeDlPopup();
        };
        const escHandler = (e) => { if (e.key === 'Escape') _closeDlPopup(); };
        setTimeout(() => {
            document.addEventListener('click', outsideClick, true);
            document.addEventListener('keydown', escHandler);
        }, 50);
        _dlPopupCleanup = () => {
            document.removeEventListener('click', outsideClick, true);
            document.removeEventListener('keydown', escHandler);
        };

        // Fetch server config to show current directory
        (async () => {
            const mdl = await MediaDLManager.check();
            if (mdl.ok) {
                const cfg = await _fetchServerConfig(mdl.token);
                if (cfg?.downloadPath && dirDisplay.isConnected) {
                    dirDisplay.textContent = cfg.downloadPath;
                    dirInput.placeholder = cfg.downloadPath;
                }
            }
        })();
    }

    // Aggressive button injection system with MutationObserver
    const persistentButtons = new Map(); // id -> { parentSelector, checkSelector, injectFn }
    let buttonObserver = null;
    let buttonCheckStarted = false;

    function registerPersistentButton(id, parentSelector, checkSelector, injectFn, pcLabel) {
        persistentButtons.set(id, { parentSelector, checkSelector, injectFn, pcLabel });
        DebugManager.log('Buttons', `Registered: ${id} (total: ${persistentButtons.size})`);
        startButtonChecker();
        // Try immediately
        tryInjectButton(id);
    }

    function unregisterPersistentButton(id) {
        const config = persistentButtons.get(id);
        if (config) {
            document.querySelector(config.checkSelector)?.remove();
        }
        persistentButtons.delete(id);
        // Clean up observer when no buttons remain
        if (persistentButtons.size === 0 && buttonObserver) {
            buttonObserver.disconnect();
            buttonObserver = null;
            buttonCheckStarted = false;
        }
    }

    function tryInjectButton(id) {
        if (!window.location.pathname.startsWith('/watch')) return false;

        const config = persistentButtons.get(id);
        if (!config) return false;

        // If button already exists anywhere in DOM, done
        if (document.querySelector(config.checkSelector)) return true;

        // Find the action buttons container (skip clarify-box copies)
        let target = null;
        const allBtnContainers = document.querySelectorAll('#top-level-buttons-computed');
        for (const el of allBtnContainers) {
            if (!el.closest('#clarify-box, ytd-info-panel-container-renderer, ytd-clarification-renderer')) {
                target = el;
                break;
            }
        }

        // Fallback: try parent containers
        if (!target) {
            const fallbacks = [
                'ytd-watch-metadata:not([hidden]) ytd-menu-renderer',
                '#above-the-fold ytd-menu-renderer',
                'ytd-watch-metadata:not([hidden]) #actions-inner',
                'ytd-watch-metadata:not([hidden]) #actions',
                '#above-the-fold #actions',
                '#below #actions',
                'ytd-watch-metadata #actions',
            ];
            for (const sel of fallbacks) {
                try {
                    const el = document.querySelector(sel);
                    if (el && !el.closest('#clarify-box, ytd-info-panel-container-renderer')) {
                        target = el;
                        break;
                    }
                } catch (e) { /* skip */ }
            }
        }

        if (!target) {
            // Only warn if we've been on the watch page long enough — the first 2s is normal
            // Polymer render lag; the 1s/2.5s retry timers will succeed without noise.
            const onPageFor = Date.now() - (tryInjectButton._pageArrival || Date.now());
            if (onPageFor > 2000) {
                if (!tryInjectButton._lastDebugTime || Date.now() - tryInjectButton._lastDebugTime > 5000) {
                    tryInjectButton._lastDebugTime = Date.now();
                    const tlbc = document.querySelector('#top-level-buttons-computed');
                    const actions = document.querySelector('#actions');
                    const menu = document.querySelector('ytd-menu-renderer');
                    const metadata = document.querySelector('ytd-watch-metadata');
                    console.warn(`[YTKit Buttons] No target for ${id}:`,
                        `#top-level-buttons-computed=${!!tlbc}${tlbc ? '(inClarify=' + !!tlbc.closest('#clarify-box') + ')' : ''}`,
                        `#actions=${!!actions}`,
                        `ytd-menu-renderer=${!!menu}`,
                        `ytd-watch-metadata=${!!metadata}`
                    );
                }
            }
            return false;
        }

        try {
            config.injectFn(target);
            DebugManager.log('Buttons', `Injected ${id} into`, target.tagName + '#' + (target.id || ''));
            // Wrap with dismiss X if a label was provided
            if (config.pcLabel) {
                const injected = document.querySelector(config.checkSelector);
                if (injected) wrapPageControl(injected, id, { label: config.pcLabel });
            }
            return true;
        } catch (e) {
            console.error(`[YTKit] Failed to inject ${id}:`, e);
            return false;
        }
    }

    // Track current video ID to clear injection tracking on video change
    let lastVideoId = null;

    function checkAllButtons() {
        if (!window.location.pathname.startsWith('/watch')) return;

        // Check if video changed
        const currentVideoId = getVideoId();
        if (currentVideoId && currentVideoId !== lastVideoId) {
            lastVideoId = currentVideoId;
            DebugManager.log('Buttons', `New video: ${currentVideoId}, ${persistentButtons.size} buttons registered`);
        }

        if (persistentButtons.size === 0) return;

        for (const id of persistentButtons.keys()) {
            tryInjectButton(id);
        }
    }

    function startButtonChecker() {
        if (buttonCheckStarted) return;
        buttonCheckStarted = true;

        // Debounce timer for observer
        let debounceTimer = null;
        let lastCheckTime = 0;
        const MIN_CHECK_INTERVAL = 500;

        // MutationObserver to detect when button container appears OR buttons are removed
        if (!buttonObserver) {
            buttonObserver = new MutationObserver((mutations) => {
                if (Date.now() - lastCheckTime < MIN_CHECK_INTERVAL) return;

                let needsRecheck = false;

                for (const m of mutations) {
                    if (m.type === 'childList' && m.addedNodes.length > 0) {
                        for (const node of m.addedNodes) {
                            if (node.nodeType === 1) {
                                if (node.id === 'top-level-buttons-computed' ||
                                    node.id === 'actions' ||
                                    node.id === 'actions-inner' ||
                                    (node.querySelector && node.querySelector('#top-level-buttons-computed'))) {
                                    needsRecheck = true;
                                    break;
                                }
                            }
                        }
                    }

                    if (m.type === 'childList' && m.removedNodes.length > 0) {
                        for (const node of m.removedNodes) {
                            if (node.nodeType === 1 && node.classList && (
                                node.classList.contains('ytkit-local-dl-btn') ||
                                node.classList.contains('ytkit-embed-btn') ||
                                node.classList.contains('ytkit-transcript-btn'))) {
                                needsRecheck = true;
                                break;
                            }
                        }
                    }

                    if (needsRecheck) break;
                }

                if (needsRecheck && !debounceTimer) {
                    debounceTimer = setTimeout(() => {
                        debounceTimer = null;
                        lastCheckTime = Date.now();
                        checkAllButtons();
                    }, 300);
                }
            });
            buttonObserver.observe(document.body, { childList: true, subtree: true });
        }

        // Initial checks — record page arrival time so the debug warning in
        // tryInjectButton fires correctly on direct (non-SPA) page loads too.
        tryInjectButton._pageArrival = Date.now();
        checkAllButtons();
        let spaTimers = [
            setTimeout(checkAllButtons, 500),
            setTimeout(checkAllButtons, 1500)
        ];

        // SPA navigation — use navigate rule system instead of separate listener
        addNavigateRule('_buttonChecker', () => {
            spaTimers.forEach(t => clearTimeout(t));
            spaTimers = [];
            lastVideoId = null;
            tryInjectButton._pageArrival = Date.now();
            checkAllButtons();
            spaTimers.push(setTimeout(checkAllButtons, 1000));
        });
    }

